// types.d.ts
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

export interface UseWeatherReturn {
  formattedTemp: string;
  formattedWind: string;
  formattedHumidity: string;
  displayUnit: string;
}

export interface CurrentWeatherProps {
  city: string;
  temp: string;
  condition: string;
  unit: string;
}

export interface WeatherDetailsProps {
  humidity: string;
  windSpeed: string;
}

