// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const WEATHER_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Clear: '☀️',
  Cloudy: '☁️',
  'Partly Cloudy': '⛅',
  Rain: '🌧️',
  Showers: '🌦️',
  Thunderstorm: '⛈️',
  Snow: '❄️',
  Mist: '🌫️',
  Default: '🌡️',
};

export const TEMPERATURE_UNITS = {
  CELSIUS: '°C',
  FAHRENHEIT: '°F',
} as const;

export const WIND_SPEED_UNITS = {
  METRIC: 'km/h',
  IMPERIAL: 'mph',
} as const;

export const DEFAULT_UNIT = TEMPERATURE_UNITS.CELSIUS;

export const LABELS = {
  HUMIDITY: 'Humidity',
  WIND_SPEED: 'Wind Speed',
  FORECAST_TITLE: '5-Day Forecast',
} as const;

export const WEEKDAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

export const FORMATTING = {
  DECIMAL_PLACES: 0,
} as const;

// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { Props, HookReturn } from './types';
import * as constants from './constants';

export function useComponent(props: Props): HookReturn {

  const displayUnit = props.unit || 'C';

  const formattedTemp = `${Math.round(props.temperature)}°${displayUnit}`;

  const formattedWind = displayUnit === 'F' 
    ? `${props.windSpeed} mph` 
    : `${props.windSpeed} km/h`;

  const formattedHumidity = `${props.humidity}%`;

  return {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    displayUnit
  };
}


