// components/CurrentWeather.tsx
import React from 'react';
import { Stack, Heading, Text, Icon } from '@ggui-ai/design/primitives';
import { CurrentWeatherProps } from './types';

/**
 * CurrentWeather component displays the city name, a large weather condition icon,
 * and the current temperature with its unit.
 */
export const CurrentWeather: React.FC<CurrentWeatherProps> = ({
  city,
  temp,
  condition,
  unit,
}) => {
  // Maps weather condition strings to design system icon names.
  const getIconName = (cond: string): string => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return 'sun';
    if (c.includes('cloud')) return 'cloud';
    if (c.includes('rain') || c.includes('drizzle')) return 'cloud-rain';
    if (c.includes('snow')) return 'cloud-snow';
    if (c.includes('storm') || c.includes('thunder')) return 'cloud-lightning';
    return 'settings'; // Fallback if no specific weather icon is found
  };

  return (
    <Stack gap="var(--ggui-spacing-2)">
      {/* City Name */}
      <Heading level={4} color="var(--ggui-color-onSurfaceVariant)">
        {city}
      </Heading>

      {/* Temperature and Icon Row */}
      <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4)">
        <Icon
          name={getIconName(condition)}
          size={48}
          color="var(--ggui-color-primary-600)"
        />

        {/* Temperature Display with unit */}
        <Stack direction="horizontal" align="start" gap="var(--ggui-spacing-1)">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            {temp}
          </Heading>
          <Text
            variant="bodyLarge"
            color="var(--ggui-color-onSurface)"
            style={{ marginTop: 'var(--ggui-spacing-2)' }}
          >
            {unit}
          </Text>
        </Stack>
      </Stack>
    </Stack>
  );
};

