// components/ForecastStrip.tsx
import React from 'react';
import { Stack, Text, Divider, Icon } from '@ggui-ai/design/primitives';
import { ForecastStripProps, ForecastItemProps } from './types';

const BUILT_IN_ICONS = [
  'check', 'x', 'chevron-down', 'chevron-up', 
  'chevron-left', 'chevron-right', 'search', 
  'plus', 'minus', 'menu', 'user', 'settings'
];

/**
 * ForecastItem renders a single day's forecast data.
 */
const ForecastItem: React.FC<ForecastItemProps> = ({ data, unit }) => {
  const isIcon = BUILT_IN_ICONS.includes(data.icon);

  return (
    <Stack align="center" gap={1}>
      <Text variant="label" color="var(--ggui-color-onSurface)">
        {data.day}
      </Text>

      {isIcon ? (
        <Icon name={data.icon} size={24} />
      ) : (
        <Text variant="bodyLarge">
          {data.icon}
        </Text>
      )}

      <Stack direction="horizontal" gap={1} align="center">
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {data.high}{unit}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {data.low}{unit}
        </Text>
      </Stack>
    </Stack>
  );
};

/**
 * ForecastStrip displays a horizontal list of forecasts separated from the header by a divider.
 */
export const ForecastStrip: React.FC<ForecastStripProps> = ({ forecast, unit }) => {
  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <div style={{ paddingTop: 'var(--ggui-spacing-4)' }}>
      <Divider margin={0} />
      <div style={{ overflowX: 'auto', paddingTop: 'var(--ggui-spacing-4)' }}>
        <Stack direction="horizontal" justify="between" gap={4}>
          {forecast.map((item, index) => (
            <ForecastItem key={item.day || index} data={item} unit={unit} />
          ))}
        </Stack>
      </div>
    </div>
  );
};

