// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Divider, Box } from '@ggui-ai/design/primitives';
import { CurrentWeather, WeatherDetails, ForecastStrip } from './components';
import { useWeather } from '../hooks/useWeather';
import type { Props, HookReturn } from './types';

export function Component(props: Props & HookReturn) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  const {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    displayUnit,
  } = useWeather(temperature, windSpeed, humidity, unit);

  return (
    <Container maxWidth="450px" padding="var(--ggui-spacing-4, 16px)">
      <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          {/* Section 1: Current Overview */}
          <CurrentWeather
            city={city}
            temp={formattedTemp}
            condition={condition}
            unit={displayUnit}
          />

          <Divider margin={0} />

          {/* Section 2: Vital Details */}
          <WeatherDetails humidity={formattedHumidity} windSpeed={formattedWind} />

          <Divider margin={0} />

          {/* Section 3: Forecast */}
          <ForecastStrip forecast={forecast} unit={displayUnit} />
        </Stack>
      </Card>
    </Container>
  );
}


// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { Component } from './components/index';

export default function Entrypoint(props: Props) {
  const state = useComponent(props);
  return <Component {...props} {...state} />;
}
